using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: Route all logging to stderr so stdout remains clean for JSON-RPC
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient for DI into tool classes
builder.Services.AddHttpClient("weather", client =>
{
    client.BaseAddress = new Uri("https://api.open-meteo.com");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public class WeatherTools(IHttpClientFactory httpClientFactory, ILogger<WeatherTools> logger)
{
    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location (e.g. 47.6)")] double latitude,
        [Description("Longitude of the location (e.g. -122.3)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching weather for ({Lat}, {Lon})", latitude, longitude);

        var client = httpClientFactory.CreateClient("weather");
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(response);
        var current = doc.RootElement.GetProperty("current");
        var temp = current.GetProperty("temperature_2m").GetDouble();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();

        return $"Temperature: {temp}°C, Wind: {wind} km/h";
    }

    [McpServerTool, Description("Get a multi-day weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("weather");
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        return await client.GetStringAsync(url, cancellationToken);
    }
}

